<div class="erp-ajustes-estoque-actions">
    <button type="button" wire:click="createAjuste" class="erp-ajustes-estoque-actions__btn" data-erp-key="F2"><span class="erp-ajustes-estoque-actions__icon erp-ajustes-estoque-actions__icon--new">+</span><span class="erp-ajustes-estoque-actions__label"><kbd>F2</kbd> | Novo</span></button>
    <button type="button" wire:click="refreshTable" class="erp-ajustes-estoque-actions__btn" data-erp-key="F5"><span class="erp-ajustes-estoque-actions__icon">↻</span><span class="erp-ajustes-estoque-actions__label"><kbd>F5</kbd> | Atualizar</span></button>
    <button type="button" wire:click="printAjustes" class="erp-ajustes-estoque-actions__btn" data-erp-key="F4"><span class="erp-ajustes-estoque-actions__icon">🖨</span><span class="erp-ajustes-estoque-actions__label"><kbd>F4</kbd> | Imprimir</span></button>
    <button type="button" wire:click="closeScreen" class="erp-ajustes-estoque-actions__btn erp-ajustes-estoque-actions__btn--close"><span class="erp-ajustes-estoque-actions__icon erp-ajustes-estoque-actions__icon--close">✕</span><span class="erp-ajustes-estoque-actions__label">Fechar</span></button>
</div>
